/* techniques q10 (48 mục) — R6 sửa lỗi */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q10"]=window.__LIBQ["tien-nghich"]["q10"]||{};window.__LIBQ["tien-nghich"]["q10"]["techniques"]={"updatedAt":"2026-07-12","count":48,"techniques":[{"id":"than-thong-nhat-nguyet-tich-hon-dao","name":"Thần thông nhật nguyệt Tịch Hồn Đạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Tịch Hồn Đạo","soHuu":["Tống Lạc Hải"],"blurb":"Thần thông mạnh nhất của Tống Lạc Hải, đặc trưng Tịch Hồn Đạo, chuyên đánh vào hồn và nguyên thần.","detail":"Hai tay bấm quyết, hư ảnh nhật nguyệt biến ảo, kết hợp tiếng gầm ẩn chứa thần thông nhắm vào nguyên thần đối phương. Đặc điểm đánh không vào thân thể mà vào hồn/nguyên thần, gây mê man tạm thời. Bị Vương Lâm phá tan bằng cơn lốc xoáy ý cảnh và quy tắc.","congNang":["Đánh vào hồn và nguyên thần đối phương, gây mê man tạm thời"],"nguoiTu":[{"ten":"Tống Lạc Hải","tuChuong":"@c1170","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1170","loai":"thi triển","importance":"normal","giaiDoan":"Tống Lạc Hải thi triển chống Vương Lâm","text":"Tống Lạc Hải thi triển thần thông mạnh nhất, hư ảnh nhật nguyệt biến ảo giữa hai tay, kèm tiếng gầm đánh vào nguyên thần Vương Lâm. Bị Vương Lâm phản kích phá tan.","anchor":"hư ảnh của nhật nguyệt biến ảo giữa hai tay, hắn thi triển, chính là thần thông mạnh nhất"}]},"nguon":["@c1170"]},{"id":"chin-loai-phap-tac-cua-da","name":"Chín loại pháp tắc trong cửa đá","cn":"","loai":"khac","loaiLabel":"Pháp tắc","phamCap":"Không rõ","hePhai":"Phong Tiên Giới","soHuu":[],"blurb":"Chín loại pháp tắc ẩn chứa bên trong cánh cửa đá khổng lồ cao vạn trượng ở trung tâm Phong Tiên Giới, có mạnh có yếu khác nhau. Theo pho tượng đá bí ẩn, Vương Lâm có thể cảm ngộ được một trong chín loại này.","detail":"Theo lời pho tượng đá bí ẩn ở cực sâu Phong Tiên Giới, cánh cửa đá cao vạn trượng tại trung tâm Phong Tiên Giới chứa chín loại pháp tắc với mức mạnh yếu khác nhau (@c1173). Sự tồn tại của chúng được hé lộ khi pho tượng đá tỉnh giấc, và Vương Lâm đang trong quá trình cảm ngộ với khả năng lĩnh hội được một trong chín loại pháp tắc này.","tabs":{"tienTrinh":[{"chuong":"@c1173","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu được đề cập","text":"Pho tượng đá bí ẩn tỉnh giấc tiết lộ cửa đá chứa chín loại pháp tắc mạnh yếu khác nhau, Vương Lâm có thể cảm ngộ được một loại.","anchor":"Trong cửa đá dù mạnh hay yếu cũng có chín loại pháp tắc, hắn có thể cảm ngộ được một loại"}]},"nguon":["@c1173"],"dacDiem":"Gồm chín loại pháp tắc với mức độ mạnh yếu khác nhau, ẩn chứa trong cánh cửa đá cao vạn trượng ở trung tâm Phong Tiên Giới (@c1173)."},{"id":"tran-phap-thong-thien-mon","name":"Trận pháp Thông Thiên Môn","cn":"通天門陣法","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Tiên giới","soHuu":[],"blurb":"Trận pháp Thông Thiên Môn là trận pháp quy mô vạn dặm do vô số tiên nhân tiên giới lập ra theo ý chỉ Viễn Cổ tiên vực, dùng để kích hoạt và tạo thành Thông Thiên Môn nghênh đón Viễn Cổ Chân Tiên hàng lâm.","detail":"Trận pháp có nguồn gốc do tiên nhân tiên giới lập theo ý chỉ Viễn Cổ tiên vực. Phạm vi trải rộng vạn dặm, với vô số tiên nhân khoanh chân ngồi trên mặt đất tạo thành trận pháp khổng lồ. Trận v hành bằng cách dời núi bốn phía và đại địa: núi đông-tây làm hai cột, dãy núi nam làm khung trên, đại địa phía bắc hóa tấm ván cửa, từ đó kích hoạt tiên môn nối liền tiên giới với Viễn Cổ tiên vực. Trận pháp xuất hiện qua ký ức cánh cửa đá, cho thấy quá trình vô số tiên nhân dựng thành Thông Thiên Môn.","thuocTinh":"Tiên","nguonGoc":"Do tiên nhân tiên giới lập theo ý chỉ Viễn Cổ tiên vực","congNang":["Dời núi đông-tây tạo hai cột, dãy núi nam làm khung trên, đại địa phía bắc hóa tấm ván cửa để dựng thành cửa @c1174","Kích hoạt Thông Thiên Môn nối tiên giới với Viễn Cổ tiên vực, nghênh đón Viễn Cổ Chân Tiên hàng lâm @c1174"],"tabs":{"tienTrinh":[{"chuong":"@c1174","loai":"xuất hiện","importance":"major","giaiDoan":"Hé lộ qua ký ức cánh cửa đá","text":"Ký ức cánh cửa đá cho thấy vô số tiên nhân tạo trận pháp vạn dặm dời bốn phía núi/đại địa xây thành Thông Thiên Môn theo ý chỉ Viễn Cổ tiên vực.","anchor":"Có rất nhiều tiên nhân đang khoanh chân ngồi trên mặt đất giống như đang tạo thành một trận pháp khổng lồ"}]},"nguon":["@c1174"],"dacDiem":"Trận pháp phạm vi vạn dặm, do vô số tiên nhân khoanh chân ngồi trên mặt đất hợp thành trận pháp khổng lồ."},{"id":"chin-luong-quy-tac-canh-cua-da","name":"Chín luồng quy tắc (cánh cửa đá)","cn":"九種規則","loai":"than-thong","loaiLabel":"Thần thông (tiềm năng)","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Vương Lâm"],"blurb":"Chín luồng quy tắc là cội nguồn cấu thành cánh cửa đá mà Vương Lâm cảm ngộ: tám luồng quy tắc ẩn trong thiên địa vờn quanh khi hắn tiếp xúc cánh cửa, cộng thêm luồng thứ chín là dấu vết năm tháng đã dị biến thành \"vĩnh hằng\". Đây được định sẵn sẽ là thần thông thứ hai của Vương Lâm.","detail":"Cánh cửa đá xuất hiện khi Vương Lâm cảm ngộ, khi ấy hắn phát hiện có tám luồng quy tắc ẩn trong thiên địa ngăn cánh cửa ngưng tụ (@c1174). Muốn ngưng tụ cánh cửa thành thần thông trong tâm thần thì phải nắm trọn cả chín luồng, nếu không sẽ phải đợi đến Toái Niết đại viên mãn. Công pháp này khác biệt hoàn toàn so với lần cảm ngộ Tàn Dạ trước đó vốn chỉ có một loại quy tắc. Điểm đặc biệt nằm ở luồng thứ chín: dấu vết năm tháng trên cánh cửa đá tiến hóa thành \"vĩnh hằng\" — cùng bản nguyên nhưng mức độ hoàn toàn khác biệt.","thuocTinh":"Năm tháng / Vĩnh hằng","yeuCau":"Nắm hết chín luồng quy tắc hoặc đạt Toái Niết đại viên mãn","congNang":["Ngưng tụ cánh cửa đá thành thần thông mới trong tâm thần (cần nắm đủ chín luồng quy tắc) @c1174"],"dacDiem":"Năm tháng dị biến thành vĩnh hằng — bản nguyên giống, mức độ khác","cacTang":[],"tabs":{"tienTrinh":[{"chuong":"@c1174","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm phát hiện chín luồng quy tắc khi cảm ngộ cánh cửa đá","text":"Vương Lâm cảm ngộ cánh cửa đá, phát hiện tám luồng quy tắc ẩn trong thiên địa ngăn cánh cửa ngưng tụ, cùng luồng thứ chín là dấu vết năm tháng dị biến thành vĩnh hằng.","anchor":"tám loại lực lượng kỳ dị, trong lúc Vương Lâm cảm ngộ thì phát hiện ra đây là loại quy tắc ẩn giấu trong thiên địa"}]},"nguon":["@c1174"]},{"id":"luu-nguyet","name":"Lưu Nguyệt","cn":"流月","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Lưu Nguyệt là thần thông thứ hai của Vương Lâm, ngộ ra từ quy tắc biến hóa thứ chín ẩn trong khí tức năm tháng trên cánh cửa đá Phong giới. Bản chất của nó là năm tháng chảy xuôi vĩnh hằng, muốn dừng lại phải có lực phá vỡ quá trình vĩnh hằng, và trong khoảnh khắc đó xuất hiện Phương Hoa.","detail":"Vương Lâm ngồi mười ngày trên cánh cửa đá trong Phong giới, tâm thần dung hợp với cánh cửa, cảm ngộ loại quy tắc biến hóa thứ chín — loại mạnh nhất, ẩn trong khí tức năm tháng, bỏ qua tám loại quy tắc khác để tập trung hoàn toàn vào loại này (@c1175). Trong quá trình cảm ngộ, y hồi tưởng ký ức gần hai ngàn năm tu đạo cùng hình bóng Vương Bình, ngộ ra bản chất tu đạo là dẫn đạo vào lòng, ngưng tụ ý cảnh, và đặt tên thần thông theo tâm tình với Vương Bình. Sau khi định danh Lưu Nguyệt trong tâm thần, y vung tay phải kích hoạt sóng dữ (@c176).","thuocTinh":"Năm tháng / Thời gian","nguonGoc":"Ngộ từ quy tắc biến hóa thứ chín trên cánh cửa đá Phong giới","dacDiem":"Năm tháng chảy xuôi vĩnh hằng, muốn dừng lại phải có lực phá vỡ quá trình vĩnh hằng, trong khoảnh khắc đó xuất hiện Phương Hoa.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1175","tangDatToi":"Mới ngộ","trangThai":"moi-ngo"}],"congNang":["Liên quan quy tắc năm tháng/thời gian, phá vỡ quá trình vĩnh hằng @c1175","Xoay ngược thời gian ký ức và tu vi mục tiêu, mỗi hơi thở tương đương 100 năm cuộn ngược","Khiến thương tích cũ trong quá khứ tái phát trên thân thể thật","Có thể biến sự thoái hóa thành vĩnh hằng, khiến tu vi giảm vĩnh viễn nếu thần thức Vương Lâm khẽ động"],"tabs":{"tienTrinh":[{"chuong":"@c1175","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm lần đầu ngộ ra","text":"Vương Lâm ngồi mười ngày trên cánh cửa đá Phong giới, tâm thần dung hợp cảm ngộ quy tắc thứ chín, ngộ ra thần thông thứ hai đặt tên Lưu Nguyệt.","anchor":"Bình nhi, thần thông thứ hai của phụ thân có thể gọi là Lưu Nguyệt được không?"},{"chuong":"@c1176","loai":"xuat-hien","importance":"major","giaiDoan":"Vương Lâm ngộ ra và đặt tên","text":"Vương Lâm trong tâm thần đặt tên thức thần thông thứ hai là Lưu Nguyệt, vung tay phải kích hoạt sóng dữ. Thần thông vô tình thử nghiệm lên đám tu sĩ Lý Nguyên Lôi: mười hai hơi thở cuộn ngược hai ngàn năm, Tịch Niết đại viên mãn rơi xuống Khuy Niết, nữ tu sĩ Đệ Nhị Bộ rơi xuống Vấn Đỉnh. Vương Lâm minh ngộ quy tắc biến hóa.","anchor":"mỗi một lần hít thở đều là một trăm năm đối với đám người"}]},"capNhatToi":"@c1175","nguon":["@c1175","@c1176"],"trangThai":"dang-dung"},{"id":"tien-thuat-bach-pham","name":"Tiên thuật Bạch Phàm","cn":"白凡仙术","loai":"tien-thuat","loaiLabel":"Tiên thuật","phamCap":"Không rõ","hePhai":"Tiên thuật","soHuu":["Vương Lâm"],"blurb":"Tiên thuật mà Vương Lâm thi triển thông qua Tam Xoa Kích, khuấy động nguyên lực thiên địa tạo lực hủy diệt diện rộng cảnh tượng như ngày tận thế.","detail":"Vương Lâm khuấy động nguyên lực thiên địa trong Tam Xoa Kích hóa thành tiên thuật Bạch Phàm, kết hợp cùng sấm sét và lửa lam tạo cảnh tượng giống ngày tận thế, quét sạch vòng vây Văn Thú tím.","congNang":["Khuấy động nguyên lực thiên địa, tạo lực hủy diệt diện rộng"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1178","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1178","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển lần đầu trong Văn Thú Triều","text":"Vương Lâm khuấy động nguyên lực thiên địa trong Tam Xoa Kích hóa thành tiên thuật Bạch Phàm, kết hợp sấm sét và lửa lam tạo cảnh tượng như ngày tận thế để mở đường cho Văn Vương.","anchor":"thanh kích khuấy động nguyên lực trong thiên địa rồi hóa thành tiên thuật Bạch Phàm"}]},"nguon":["@c1178"]},{"id":"co-than-chi-the","name":"Cổ Thần chi thể","cn":"古神之体","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Vương Lâm phóng đại thân thể thành người khổng lồ vài trăm trượng, bùng ra khí tức viễn cổ khuấy động thiên địa, đồng thời pháp bảo cũng phóng to theo.","detail":"Thần thông thuộc hệ Cổ Thần, cho phép Vương Lâm phóng to thân thể lên vài trăm trượng. Khi thi triển, khí tức viễn cổ bùng ra khuấy động thiên địa, pháp bảo cầm trên tay (Tam Xoa Kích) cũng phóng đại theo tỉ lệ tương ứng.","congNang":["Phóng đại thân thể và pháp bảo, tăng lực chiến đấu","Bùng ra khí tức viễn cổ khuấy động thiên địa"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1178","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1178","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển trong Văn Thú Triều","text":"Vương Lâm phóng to thân thể Cổ Thần lên vài trăm trượng, Tam Xoa Kích cũng phóng to theo, bùng ra khí tức viễn cổ khuấy động thiên địa để chiến đấu với đám Văn Thú tím.","anchor":"thân thể hắn đột nhiên được phóng to một cách điên cuồng, khoảnh khắc sau đã trở thành một người khổng lồ vài trăm trượng"}]},"nguon":["@c1178"]},{"id":"mot-chi-thien-van","name":"Một Chỉ Thiên Vận","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thiên Vận","soHuu":["Vương Lâm"],"blurb":"Thần thông dung hợp linh hồn Thiên Vận Tử trong tâm thần, xuất thần thông uy lực kinh hoàng. Không phải tiên pháp, tiêu hao hồn phách Nghịch Hành giả Thiên Vận Tử và nguyên lực người dùng.","detail":"Không phải tiên pháp, không tiêu hao tiên lực. Cơ chế: dung hợp linh hồn Thiên Vận Tử trong tâm thần rồi xuất ra. Tiêu hao lực lượng hồn phách Nghịch Hành giả Thiên Vận Tử cùng nguyên lực của Vương Lâm. Uy lực kém hơn khi chính Thiên Vận Tử thi triển do tu vi khác biệt và phương pháp khác nhau. Cần tu vi bản thân tăng cường mới tiện tay thi triển.","thuocTinh":"Linh hồn / hồn phách","nguonGoc":"Từ linh hồn Nghịch Hành giả Thiên Vận Tử bị Vương Lâm dung hợp","yeuCau":"Phải có hồn phách Thiên Vận Tử trong tâm thần; tiêu hao nguyên lực người dùng","uyLuc":"Uy lực kinh hoàng, gây kinh hãi cho tu sĩ Toái Niết, nhưng kém hơn khi chính Thiên Vận Tử thi triển","dacDiem":"Không phải tiên pháp; tiêu hao hồn phách Nghịch Hành giả + nguyên lực; uy lực tỉ lệ thuận tu vi người dùng","congNang":["Dung hợp linh hồn Thiên Vận Tử xuất thần thông, gây uy lực phá hủy cực lớn @c1185"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1184","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1185","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Giải thích cơ chế hoạt động","text":"Lần đầu giải thích rõ cơ chế: dung hợp linh hồn Thiên Vận Tử, tiêu hao hồn phách Nghịch Hành giả và nguyên lực Vương Lâm, không phải tiên pháp, uy lực kém bản gốc.","anchor":"tiêu hao chính là lực lượng trong hồn phách Nghịch Hành giả Thiên Vận Tử, hơn nữa cũng có cả nguyên lực Vương Lâm"}]},"capNhatToi":"@c1185","nguon":["@c1185"]},{"id":"ho-hon-cuu-chuyen","name":"Hổ Hồn Cửu Chuyển","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thanh Vân Tông","soHuu":["Đàn ông áo xanh Thanh Vân Tông"],"blurb":"Thần thông của Thanh Vân Tông, triệu hồi mãnh hổ chín đầu màu đỏ trăm trượng từ vòng xoáy, chín đầu tấn công từ chín phương hướng.","detail":"Thi triển tạo vòng xoáy khổng lồ, từ trong đó huyễn hóa ra mãnh hổ chín đầu màu đỏ trăm trượng, mỗi đầu tấn công từ một phương. Bị Vương Lâm dùng lửa lam phá vỡ ba đầu rồi đánh tan hoàn toàn.","thuocTinh":"Biến hóa","nguonGoc":"Thanh Vân Tông","congNang":["Triệu hồi mãnh hổ chín đầu màu đỏ trăm trượng tấn công từ chín phương hướng"],"nguoiTu":[{"ten":"Đàn ông áo xanh Thanh Vân Tông","tuChuong":"@c1186","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1186","loai":"thi triển","importance":"normal","giaiDoan":"Đàn ông áo xanh thi triển tại đại hội","text":"Đàn ông áo xanh Thanh Vân Tông thi triển Hổ Hồn Cửu Chuyển triệu mãnh hổ chín đầu tấn công Vương Lâm, nhưng bị lửa lam phá vỡ ba đầu rồi bị đánh tan hoàn toàn.","anchor":"Hư ảnh của một mãnh hổ chín đầu màu đỏ đột nhiên huyễn hóa ra trong vòng xoáy"}]},"nguon":["@c1186"]},{"id":"thien-dia-chi-hoa","name":"Thiên địa chi hỏa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thiên địa chi hỏa là thần thông hỏa hệ của Vương Lâm, có khả năng triệu tập toàn bộ hỏa nguyên lực trong thiên địa cùng hỏa nguyên thần trong cơ thể các tu sĩ hệ hỏa về phía mình, biến chúng thành biển lửa dưới quyền khống chế.","detail":"Khi thi triển, tất cả hỏa nguyên lực trong thiên địa cùng hỏa nguyên thần trong cơ thể các tu sĩ hệ hỏa đều mất kiểm soát, tự động bay ra khỏi cơ thể hướng về Vương Lâm (@c1186). Ngay cả trưởng lão hệ hỏa Vô Cực tông cũng suýt mất hỏa nguyên thần. Thần thông này thể hiện Vương Lâm đã đạt tới cảnh giới người điều khiển ngọn lửa, khi mọi ngọn lửa trong thiên địa đều phải nghe theo hiệu lệnh của y.","thuocTinh":"Hỏa","congNang":["Triệu hút mọi hỏa nguyên lực thiên địa và trong cơ thể tu sĩ hệ hỏa về mình, biến thành biển lửa @c1186","Khống chế lửa toàn trường, khiến hỏa nguyên thần trong cơ thể người khác mất kiểm soát bay ra ngoài @c1186"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1186","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1186","loai":"thi triển","importance":"major","giaiDoan":"Vương Lâm thi triển tại đại hội Vô Cực tông","text":"Vương Lâm thi triển Thiên địa chi hỏa, toàn bộ tu sĩ hệ hỏa trên khán đài mất kiểm soát hỏa nguyên lực, trưởng lão hệ hỏa Vô Cực tông suýt mất hỏa nguyên thần.","anchor":"tất cả đều trở nên điên cuồng, muốn lao ra khỏi cơ thể giống như đang được kêu gọi"}]},"nguon":["@c1186"],"uyLuc":"Khi thi triển, toàn bộ tu sĩ hệ hỏa trên khán đài mất kiểm soát hỏa nguyên lực, ngay cả trưởng lão hệ hỏa Vô Cực tông cũng suýt mất hỏa nguyên thần @c1186","dacDiem":"Đạt cảnh giới người điều khiển ngọn lửa, mọi ngọn lửa trong thiên địa đều phải nghe hiệu lệnh"},{"id":"rut-hon","name":"Thần thông rút hồn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đệ Tam Bộ thần thông","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông rút hồn là một trong bốn đại thần thông tự ngộ thuộc Đệ Tam Bộ, chuyên rút linh hồn tinh không (không hồn). Không thể học từ người khác mà chỉ dựa vào cơ duyên minh ngộ, trong Vân Hải tinh vực không quá ba người thi triển được.","detail":"Thần thông rút hồn xếp thứ hai trong bốn loại đại thần thông giảng thiên ngộ địa được truyền thuyết trong giới tu sĩ Đệ Nhị Bộ, chỉ sau Súc Địa Thành Thốn. Đây là thức thuộc tầng không hồn — rút linh hồn tinh không,ế tiếp sau tinh hồn. Đặc trưng của thần thông này là hoàn toàn dựa vào cơ duyên tự mình minh ngộ, không thể truyền thụ hay học từ người khác. Vương San San xác nhận thuật rút hồn thuộc Đệ Tam Bộ, và trong Vân Hải tinh vực không quá ba người có thể thi triển được @c1188.","congNang":["Rút linh hồn đối phương, khiến đối thủ thất bại chỉ bằng một thức","Thuộc tầng không hồn — rút linh hồn tinh không (sau tinh hồn)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1188","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1188","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Xác nhận thuộc Đệ Tam Bộ, một trong bốn đại thần thông tự ngộ","text":"Vương San San xác nhận thuật rút hồn thuộc Đệ Tam Bộ. Trong Vân Hải tinh vực không quá ba người thi triển được. Là một trong bốn đại thần thông tự ngộ cùng Súc Địa Thành Thốn.","anchor":"Truyền thuyết này nói về những gì tu sĩ Đệ Nhị Bộ giảng thiên ngộ địa, có thể tự mình hiểu ra bốn loại đại thần thông"}]},"nguon":["@c1188"],"dacDiem":"Một trong bốn đại thần thông tự ngộ, không thể học mà chỉ dựa cơ duyên minh ngộ; trong Vân Hải tinh vực không quá ba người thi triển được @c1188."},{"id":"bon-dai-than-thong-tu-ngo","name":"Bốn đại thần thông tự ngộ","cn":"","loai":"than-thong","loaiLabel":"Hệ thống thần thông","phamCap":"","hePhai":"","soHuu":[],"blurb":"Truyền thuyết trong tu sĩ Đệ Nhị Bộ: bốn loại đại thần thông giảng thiên ngộ địa, tự mình minh ngộ, không thể học. Hai loại đã biết là Súc Địa Thành Thốn (thứ nhất) và rút hồn (thứ hai), hai loại còn lại chưa tiết lộ.","detail":"Tu sĩ Đệ Nhị Bộ có truyền thuyết về bốn loại đại thần thông không nên học mà hoàn toàn dựa vào cơ duyên tự ngộ. Thứ tự: Súc Địa Thành Thốn xếp thứ nhất, rút hồn xếp thứ hai, hai loại còn lại chưa được công bố.","nguon":["@c1188"]},{"id":"an-ky-dai-truyen-thua-thanh-nu-con-hu","name":"Ấn ký đại truyền thừa thánh nữ Côn Hư","cn":"","loai":"than-thong","loaiLabel":"Thần thông / Truyền thừa","phamCap":"","hePhai":"Côn Hư","soHuu":["Mộc Băng Mi"],"blurb":"Phương pháp đại truyền thừa của thánh nữ Côn Hư. Dùng hai ngón tay tạo ấn ký cổ quái, triệu hình ảnh Lưu Ly Bảo Bình hư ảo phá uy áp đối phương.","detail":"Mộc Băng Mi thi triển ấn ký này khi đối mặt uy áp tông chủ Vô Cực tông. Hình ảnh Lưu Ly Bảo Bình hư ảo xuất hiện bên ngoài thân thể, đánh văng uy áp. Tuy nhiên vì thân thể nàng từng tan vỡ nên thi triển khiến vết thương nặng thêm.","congNang":["Triệu hình ảnh Lưu Ly Bảo Bình hư ảo","Phá uy áp cường giả"],"nguoiTu":[{"ten":"Mộc Băng Mi","tuChuong":"@c1188","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1188","loai":"thi-trien","importance":"normal","giaiDoan":"Mộc Băng Mi thi triển lần đầu","text":"Mộc Băng Mi lộ tu vi Toái Niết, thi triển ấn ký triệu Lưu Ly Bảo Bình hư ảo phá uy áp tông chủ Vô Cực tông, nhưng vết thương nặng thêm.","anchor":"khoảnh khắc khi ấn ký cổ quái này xuất hiện thì lập tức một hình ảnh Lưu Ly Bảo Bình hư ảo xuất hiện ngoài thân thể"}]},"nguon":["@c1188"]},{"id":"than-thong-thu-hai-vuong-lam","name":"Thần thông thứ hai (Vương Lâm)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông thứ hai là thần thông do Vương Lâm minh ngộ, uy lực chưa hoàn mỹ nhưng sở hữu tác dụng đặc biệt: chủ động thúc đẩy, kích hoạt Tàn Dạ mà không cần chờ khoảnh khắc đặc biệt.","detail":"Vương Lâm minh ngộ thần thông thứ hai sau khi nuốt Đạo quả khiến tu vi tăng mạnh. Tác dụng chính là thúc đẩy, kích hoạt Tàn Dạ một cách chủ động với thời gian thi triển rất ngắn. Trong trận đối đầu lão già tóc trắng (@c1189), Vương Lâm dùng thần thông này để chủ động kích hoạt Tàn Dạ. Uy lực chưa đạt mức hoàn mỹ và tên gọi chưa được tiết lộ.","congNang":["Thúc đẩy, kích hoạt Tàn Dạ chủ động mà không cần chờ khoảnh khắc đặc biệt @c1189"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1189","tangDatToi":"Chưa hoàn mỹ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1189","loai":"xuất hiện","importance":"major","giaiDoan":"Minh ngộ và lần đầu sử dụng","text":"Vương Lâm minh ngộ thần thông thứ hai, dùng nó để chủ động kích hoạt Tàn Dạ trong trận đối đầu lão già tóc trắng áo xám Vô Cực tông. Uy lực chưa hoàn mỹ nhưng đã đủ thúc đẩy Tàn Dạ phá vỡ mạng lưới sơ quy tắc.","anchor":"thần thông này có thể giúp hắn không cần chờ đợi khoảnh khắc đặc biệt mà có thể thúc đẩy thần thông Tàn Dạ"}]},"nguon":["@c1189"],"dacDiem":"Thời gian thi triển rất ngắn; uy lực chưa đạt mức hoàn mỹ."},{"id":"mang-luoi-so-quy-tac","name":"Mạng lưới sơ quy tắc","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"","soHuu":["Thái thượng trưởng lão Vô Cực tông"],"blurb":"Thần thông của lão già tóc trắng áo xám Vô Cực tông, huyễn hóa mạng lưới từ sơ quy tắc màu đỏ bao phủ cả thiên địa nhằm phong ấn đối phương.","detail":"Lão già vỗ tay, những luồng sáng đỏ giao thoa tạo thành mạng lưới cực lớn bao phủ thiên địa, biến đối phương thành con cá bị lưới trong biển cả. Bị Tàn Dạ của Vương Lâm phá vỡ hoàn toàn.","congNang":["Phong ấn/bắt giữ đối phương bằng mạng lưới sơ quy tắc bao phủ thiên địa"],"nguoiTu":[{"ten":"Thái thượng trưởng lão Vô Cực tông","tuChuong":"@c1189","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1189","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển nhằm trấn áp Vương Lâm","text":"Lão già tóc trắng áo xám thi triển mạng lưới sơ quy tắc bao phủ thiên địa nhằm cưỡng bức Vương Lâm khuất phục, nhưng bị Tàn Dạ phá vỡ hoàn toàn.","anchor":"những luồng sáng này giao thoa vào nhau trong thiên địa tạo thành một mảng lưới cực lớn"}]},"nguon":["@c1189"]},{"id":"tran-phap-tu-chan-tinh-vo-cuc-tong","name":"Trận pháp trên tu chân tinh (Vô Cực Tông)","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Vô Cực Tông","soHuu":["Vô Cực Tông"],"blurb":"Trận pháp được kích hoạt trên tu chân tinh nơi các tông phái đóng, khống chế ra vào — không có lệnh bài thì không thể rời đi nhưng có thể đi vào.","detail":"Trận pháp khổng lồ mở ra bên trên tu chân tinh, kiểm soát lưu thông tu sĩ. Cần lệnh bài chuyên dụng mới ra được, nhưng cho phép tự do đi vào.","congNang":["Khống chế ra/vào tu chân tinh, cần lệnh bài mới rời đi"],"tabs":{"tienTrinh":[{"chuong":"@c1192","loai":"xuất hiện","importance":"normal","giaiDoan":"Được kích hoạt","text":"Trận pháp được mở ra bên trên tu chân tinh nơi các tông phái ở, khống chế việc ra vào.","anchor":"một trận pháp kh*ng b* lập tức được mở ra bên trên tu chân tinh"}]},"nguon":["@c1192"]},{"id":"luan-hoi-dai-tran","name":"Luân Hồi đại trận","cn":"轮回大阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Thần Tông","soHuu":["Thủy Đạo Tử"],"blurb":"Trận pháp cần chín mặt Vạn Cổ Luân Hồi Kính làm trận cụ, do Thủy Đạo Tử đang tế luyện nhằm phong tỏa linh hồn, bẫy chủ nhân Thần Tông dù chuyển thế trùng sinh hay giấu hồn trong Thiên Nghịch cũng không thoát.","detail":"Thủy Đạo Tử quyết định tế luyện chín mặt Vạn Cổ Luân Hồi Kính để bày ra Luân Hồi đại trận. Mục đích là phong tỏa linh hồn, ngăn đối phương chạy thoát — dù cựu chủ nhân Thần Tông đã chuyển thế trùng tu hay giấu hồn trong Thiên Nghịch đều không thể thoát khỏi trận này. Trận pháp chưa hoàn thành, đang trong giai đoạn tế luyện trận cụ.","nguon":["@c1193"]},{"id":"dai-tran-phong-gioi","name":"Đại trận Phong giới","cn":"封界大阵","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":[],"blurb":"Đại trận ngăn cách Nội giới và Ngoại giới, phá vỡ cần thực lực cực lớn.","detail":"Đại trận phong ấn ranh giới giữa Nội giới và Ngoại giới. Thác Sâm đã phá vỡ đại trận này để đi ra Ngoại giới truy tìm Vương Lâm, nhưng sau đó không đủ thực lực để mở lại trong thời gian ngắn.","congNang":["Ngăn cách Nội giới và Ngoại giới, phong ấn lối đi giữa hai giới"],"tabs":{"tienTrinh":[{"chuong":"@c1195","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị Thác Sâm phá vỡ","text":"Vương Lâm phân tích Thác Sâm đã phá vỡ đại trận Phong giới để đi ra Ngoại giới. Hiện Thác Sâm không đủ thực lực mở lại đại trận trong thời gian ngắn.","anchor":"tên Thác Sâm này không biết dùng phương pháp nào nhưng đã phá vỡ đại trận Phong giới và đi đến. Ngoại giới"}]},"nguon":["@c1195"]},{"id":"than-thong-phan-than-thanh-nu-con-hu","name":"Thần thông phân thân thánh nữ Côn Hư","cn":null,"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thuật thần thông mạnh nhất Côn Hư","hePhai":"Côn Hư Cảnh","soHuu":["Mộc Băng Mi"],"blurb":"Thần thông thiên đạo tạo phân thân của thánh nữ Côn Hư, xưa nay chỉ một người thành công.","detail":"Phân thân thánh nữ Côn Hư phải trải qua thần thông thiên đạo, từ xưa tới nay chỉ một người thành công. Mộc Băng Mi đã dung nhập đạo niệm của mình vào phân thân, nhưng cuối cùng thua Liễu Mi nên đạo tâm bất viên mãn, khiến thuật thần thông mạnh nhất của Côn Hư xuất hiện vết nứt. Vết nứt chính là Liễu Mi / Vương Lâm / Vương Bình — khi Mộc Băng Mi chọn đối mặt thay vì né tránh, đạo tâm dần viên mãn trở lại.","nguon":["@c1196"]},{"id":"thoi-dien-thien-van-tu","name":"Thôi diễn (năng lực Thiên Vận Tử)","cn":null,"loai":"than-thong","loaiLabel":"Thần thông","phamCap":null,"hePhai":null,"soHuu":["Thiên Vận Tử","Vương Lâm"],"blurb":"Năng lực cưỡng chế thôi diễn để nhìn trước biến cố tương lai, thuộc về Thiên Vận Tử.","detail":"Vương Lâm vào mật thất bế quan, kết hợp thần thức với Thiên Vận Tử trong nguyên thần, không phải để nghênh chiến mà để mượn năng lực thôi diễn cưỡng chế nhìn ra biến cố đang tới trong Vân Hải tinh vực. Đây là khả năng đặc hữu của Thiên Vận Tử, cho phép suy đoán sự kiện sắp xảy ra.","nguon":["@c1196"]},{"id":"thuat-phap-tinh-toan-thien-dia-nghich-hanh-gia","name":"Thuật pháp tính toán thiên địa của Nghịch Hành Giả","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Nghịch Hành Giả","soHuu":["Vương Lâm"],"blurb":"Thuật pháp tính toán thiên địa từ Nghịch Hành Giả, cần thạch châu mô phỏng Thiên Nghịch làm môi giới để triệu hồi; dùng thân mình làm thiên địa để thôi diễn tương lai, tìm đường sinh cơ.","detail":"Thuật pháp có nguồn gốc từ Nghịch Hành Giả, được Vương Lâm triệu hồi bằng cách phá hủy thạch châu mô phỏng Thiên Nghịch. Khi thi triển, ánh sáng bảy màu bao phủ rồi tan vỡ thành vòng xoáy bảy màu bị hút vào miệng. Người thi triển dùng thân mình làm thiên địa để thôi diễn ra đường sinh cơ, lực lượng bùng ra xé rách sương mù, cho thấy hình ảnh Lưu Kim Bưu — đường sống duy nhất (@c1197).","congNang":["Tính toán thiên địa, thôi diễn tương lai để tìm đường sống (@c1197)","Dùng thân mình làm thiên địa làm nền tảng thôi diễn (@c1197)","Triệu hồi qua môi giới là thạch châu mô phỏng Thiên Nghịch bị phá hủy (@c1197)"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1197","tangDatToi":"","trangThai":"triệu hồi qua thạch châu"}],"tabs":{"tienTrinh":[{"chuong":"@c1197","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu triệu hồi","text":"Vương Lâm phá hủy thạch châu mô phỏng Thiên Nghịch để triệu hồi thuật pháp, dùng thân mình làm thiên địa thôi diễn ra đường sinh cơ duy nhất — hình ảnh Lưu Kim Bưu.","anchor":"Triệu hồi thuật pháp tính toán thiên địa của Nghịch Hành Giả"}]},"nguon":["@c1197"],"uyLuc":"Lực lượng bùng ra xé rách sương mù, thôi diễn hiển lộ đường sinh cơ duy nhất (@c1197).","dacDiem":"Cần phá hủy thạch châu mô phỏng Thiên Nghịch làm môi giới; khi thi triển hện ánh sáng bảy màu tan thành vòng xoáy bị hút vào miệng, lấy thân mình làm thiên địa."},{"id":"nang-luc-du-doan-thien-dia-thien-van-tu","name":"Năng lực dự đoán thiên địa của Thiên Vận Tử","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Chưa rõ","hePhai":"Thiên Vận Tử","soHuu":["Thiên Vận Tử","Vương Lâm"],"blurb":"Năng lực bản thể ẩn giấu trong linh hồn Thiên Vận Tử, cho phép dự đoán các kịch bản tương lai của thiên địa. Khi được kích hoạt, nó thôi diễn hàng loạt viễn cảnh sắp tới, dù các kịch bản đều bị sương mù và lực lượng bí ẩn che giấu.","detail":"Đây là năng lực bản thể tồn tại trong linh hồn Thiên Vận Tử. Vương Lâm dung hợp tâm thần với linh hồn Thiên Vận Tử để cưỡng chế thôi diễn tương lai, nhờ đó nhìn thấy hàng loạt kịch bản sắp diễn ra của thiên địa (@c1197). Tuy nhiên các viễn cảnh này bị sương mù cùng một lực lượng bí ẩn che giấu, và tất cả kịch bản đều dẫn đến cái chết.","congNang":["Dự đoán, thôi diễn các kịch bản tương lai của thiên địa (@c1197)","Cưỡng chế thôi diễn tương lai thông qua dung hợp tâm thần với linh hồn Thiên Vận Tử, nhìn thấy hàng loạt kịch bản sắp tới (@c197)"],"tabs":{"tienTrinh":[{"chuong":"@c1197","loai":"thi triển","importance":"major","giaiDoan":"Vương Lâm khai thác năng lực qua dung hợp","text":"Vương Lâm dung hợp tâm thần với linh hồn Thiên Vận Tử, cưỡng chế thôi diễn tương lai; nhìn thấy hàng loạt kịch bản đều kết thúc bằng cái chết.","anchor":"muốn dùng năng lực dự đoán thiên địa ẩn giấu trong bản thể linh hồn Thiên Vận Tử để cưỡng chế thôi diễn"}]},"nguon":["@c1197"],"dacDiem":"Các kịch bản tương lai thôi diễn ra đều bị sương mù cùng lực lượng bí ẩn che giấu, và tất cả đều dẫn đến cái chết."},{"id":"tieng-rong-co-than","name":"Tiếng rống Cổ Thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Tiếng rống Cổ Thần là thần thông huyết mạch của vương tộc Cổ Thần, tiếng rống mang uy lực kinh thiên động địa. Nó có thể trực tiếp diệt tu sĩ cấp Toái Niết sơ kỳ và làm trọng thương đến tận Toái Niết đại viên mãn ở khoảng cách gần.","detail":"Đây là năng lực bẩm sinh của vương tộc Cổ Thần, chỉ kích hoạt khi huyết mạch đạt gần lục tinh trở lên. Vương Lâm với thân phận vương tộc Cổ Thần gần lục tinh có thể phát ra tiếng rống kinh thiên động địa mang uy lực âm ba. Uy lực tăng theo cấp bậc huyết mạch Cổ Thần: trực tiếp đánh tan tu sĩ Toái Niết sơ kỳ, trọng thương Toái Niết trung kỳ, làm Toái Niết hậu kỳ thất khiếu chảy máu, vàngay cả Toái Niết đại viên mãn ở khoảng cách gần cũng bị thương.","thuocTinh":"huyết mạch Cổ Thần","nguonGoc":"Năng lực bẩm sinh của vương tộc Cổ Thần, kích hoạt khi huyết mạch đạt gần lục tinh","yeuCau":"Huyết mạch vương tộc Cổ Thần gần lục tinh","uyLuc":"Diệt Toái Niết sơ kỳ trực tiếp, trọng thương Toái Niết trung kỳ, làm Toái Niết hậu kỳ thất khiếu chảy máu, và ở khoảng cách gần thương được cả Toái Niết đại viên mãn.","dacDiem":"Tiếng rống âm ba, uy lực tăng theo cấp bậc huyết mạch Cổ Thần.","congNang":["Phát tiếng rống kinh thiên diệt hoặc trọng thương tu sĩ cấp Toái Niết trong phạm vi gần","Đánh tan con rết ngàn trượng triệu ra từ ngọc bội Lưu Kim Bưu @c1199"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1199","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1199","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu sử dụng","text":"Vương Lâm dùng tiếng rống Cổ Thần đánh tan con rết ngàn trượng từ ngọc bội Lưu Kim Bưu, thể hiện uy lực kinh thiên của huyết mạch vương tộc gần lục tinh.","anchor":"chính là tiếng rống Cổ Thần. Vương Lâm thân là vương tộc Cổ Thần đã gần lục tinh, tiếng gầm này kinh thiên động địa"}]},"capNhatToi":"@c1199","nguon":["@c1199"]},{"id":"co-dai-than-thong-phan-than","name":"Cổ đại thần thông phân thần","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Cổ đại thần thông","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Cổ đại thần thông phân thần là công pháp cho phép phân tách trăm phân thân hoạt động độc lập, mỗi phân thần mang một chút năng lực Cổ Thần. Vương Lâm thi triển được thần thông này khi Cổ Thần tinh thứ sáu có dấu hiệu khôi phục.","detail":"Cổ đại thần thông phân thần vận hành theo khẩu quyết \"Thiên địa vô thường, ngưng tụ trăm thân, cổ đại thần thông\". Khi thi triển, Vương Lâm phóng ra trăm luồng khí tức trắng sữa từ trán, mỗi luồng hóa thành một phân thần. Điều kiện thi triển là Cổ Thần tinh thứ sáu phải có dấu hiệu khôi phục. Tại chương 1201, Vương Lâm chính thức thi triển thần thông này nhờ tinh thứ sáu khôi phục, phân ra trăm phân thân hoạt động độc lập, mỗi phân thần đều mang năng lực của Cổ Thần.","thuocTinh":"Cổ Thần","yeuCau":"Cổ Thần tinh thứ sáu có dấu hiệu khôi phục","dacDiem":"Phân trăm phân thân, mỗi phân thần có năng lực Cổ Thần","trangThai":"Vương Lâm đã thi triển thành công","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1201","tangDatToi":"Thi triển thành công","trangThai":"dang-tu"}],"congNang":["Phân tách trăm phân thân hoạt động độc lập, mỗi phân thần mang một chút năng lực Cổ Thần @c1201","Thi triển bằng cách phóng trăm luồng khí tức trắng sữa từ trán, mỗi luồng hóa thành một phân thần","Cần Cổ Thần tinh thứ sáu có dấu hiệu khôi phục mới thi triển được @c1201"],"tabs":{"tienTrinh":[{"chuong":"@c1201","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm thi triển cổ đại thần thông phân trăm phân thần nhờ Cổ Thần tinh thứ sáu có dấu hiệu khôi phục. Phái trăm phân thần đi khắp hơn nửa tinh vực cấp năm, trong hai ngày kéo trăm man hoang đại lục về ghép thành trận pháp.","anchor":"Thiên địa vô thường, ngưng tụ trăm thân, cổ đại thần thông"}]},"capNhatToi":"@c1201","nguon":["@c1201"],"uyLuc":"Mỗi phân thần có lực lượng đủ mạnh để đẩy man hoang đại lục di chuyển trong tinh không."},{"id":"tran-phap-tram-dai-luc","name":"Trận pháp trăm đại lục","cn":"","loai":"bi-thuat","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Trận pháp khổng lồ do Vương Lâm dùng trăm phân thần kéo trăm man hoang đại lục ghép quanh đại lục mình đang ở, lấy các đại lục làm khung mà thành. Kết hợp tam đại cấm chế Phá Diệt Cấm, Sinh Tử Cấm và Tuế Nguyệt Cấm, đủ sức khiến tu sĩ Đệ Tam Bộ không dễ xâm nhập.","detail":"Trận pháp trăm đại lục ra đời khi Vương Lâm dùng trăm phân thần kéo trăm man hoang đại lục về ghép quanh đại lục mình đang ở, lấy chính các đại lục làm khung tạo thành một trận pháp khổng lồ (@c1201). Trên nền khung ấy, ông bao phủ tam đại cấm chế gồm Phá Diệt Cấm, Sinh Tử Cấm và Tuế Nguyệt Cấm. Ba cấm chế dung hợp tạo uy lực kinh thiên động địa, đóng vai trò bố phòng chiến trường khiến tu sĩ Đệ Tam Bộ không dễ phá. Từ xa nhìn, trận pháp giống một bộ tộc trên Thái Cổ Tinh Thần.","congNang":["Bố phòng chiến trường, dùng tam cấm dung hợp khiến tu sĩ Đệ Tam Bộ không dễ phá @c1201"],"tabs":{"tienTrinh":[{"chuong":"@c1201","loai":"xuất hiện","importance":"major","giaiDoan":"Lập trận","text":"Vương Lâm kéo trăm man hoang đại lục ghép thành trận pháp, bao phủ Phá Diệt Cấm, Sinh Tử Cấm và Tuế Nguyệt Cấm. Đến ngày thứ năm hoàn thành, tuyên bố dù tu sĩ Đệ Tam Bộ cũng không dễ giết mình.","anchor":"Tam đại cấm chế dung hợp, uy lực kinh thiên động địa"}]},"capNhatToi":"@c1201","nguon":["@c1201"],"uyLuc":"Tam đại cấm chế dung hợp tạo uy lực kinh thiên động địa, khiến tu sĩ Đệ Tam Bộ không dễ xâm nhập.","dacDiem":"Lấy trăm man hoang đại lục làm khung, bao phủ tam đại cấm chế Phá Diệt Cấm, Sinh Tử Cấm và Tuế Nguyệt Cấm; từ xa nhìn giống bộ tộc trên Thái Cổ Tinh Thần."},{"id":"phu-van-thuat","name":"Phù Văn Thuật","cn":"符文术","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Phù Tộc","soHuu":["Vương Lâm"],"blurb":"Thần thông do Phù Tộc Thánh Tổ truyền thụ, dùng chú ngữ tạo Phù Văn trên da thú, hút toàn bộ máu thịt tinh hoa sinh linh hóa thành Phù Văn huyết sắc có uy lực kinh thiên.","detail":"Vương Lâm thi triển Phù Văn Thuật bằng chú ngữ, hút toàn thân tinh hoa mãnh thú trên gần trăm man hoang đại lục hóa thành Phù Văn huyết sắc trên da thú. Uy áp đủ hủy diệt tu sĩ Toái Niết hậu kỳ. Nguồn gốc từ Phù Tộc Thánh Tổ truyền thụ, Tháp Sơn từng chia sẻ lĩnh ngộ cho Vương Lâm.","thuocTinh":"Phù Văn","nguonGoc":"Phù Tộc Thánh Tổ truyền thụ, Tháp Sơn chia sẻ lĩnh ngộ","congNang":["Lấy toàn thân tinh hoa mãnh thú hóa thành Phù Văn huyết sắc, uy lực kinh thiên"],"uyLuc":"Uy áp đủ hủy diệt tu sĩ Toái Niết hậu kỳ","dacDiem":"Cần rất nhiều lực lượng sinh linh","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1202","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1202","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển quy mô lớn","text":"Vương Lâm thi triển Phù Văn Thuật trên gần trăm man hoang đại lục, hút máu thịt tinh hoa toàn bộ mãnh thú hóa thành Phù Văn huyết sắc, tiếng kêu thảm thiết truyền khắp tinh vực cấp năm.","anchor":"Phù Văn dùng da thú luyện hóa thành, lấy toàn thân tinh hoa của mãnh thú mà động rồi hóa thành Phù Văn"}]},"nguon":["@c1202"]},{"id":"ngan-van-kiem-khi-hoa-mot-chi","name":"Ngàn vạn kiếm khí hóa thành một chỉ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Sát chiêu của Vương Lâm, ngưng tụ ngàn vạn kiếm khí thành một chỉ tấn công, là đòn tấn công đầu tiên chuẩn bị cho trận tử chiến với Đệ Tam Bộ.","detail":"Đòn tấn công đầu tiên Vương Lâm chuẩn bị cho trận chiến với Đệ Tam Bộ. Ngưng tụ ngàn vạn kiếm khí thành một chỉ, nằm trong ba sát chiêu cực mạnh đủ giết tu sĩ Thiên Nhân Suy Kiếp.","congNang":["Ngưng tụ ngàn vạn kiếm khí thành một chỉ tấn công"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1202","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1202","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu đề cập","text":"Vương Lâm chuẩn bị sát chiêu ngàn vạn kiếm khí hóa thành một chỉ làm đòn tấn công đầu tiên cho trận sinh tử với Đệ Tam Bộ.","anchor":"Ngàn vạn kiếm khí hóa thành một chỉ, đây là đòn tấn công đầu tiên ta chuẩn bị"}]},"nguon":["@c1202"]},{"id":"dai-tu-tai-bang-hoi-dao","name":"Đại Tự Tại Băng Hội Đạo","cn":"大自在崩毁道","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đệ Tam Bộ","hePhai":"Đệ Tam Bộ","soHuu":["Thủy Đạo Tử"],"blurb":"Thần thông của Thủy Đạo Tử — biến giọng nói bình tĩnh thành tiếng gầm rống hủy diệt, dùng âm thanh vô hình làm sóng xung kích phá tan pháp thuật và xé đôi tinh vực.","detail":"Thủy Đạo Tử vung tay thi triển, giọng nói bình tĩnh biến thành tiếng gầm rống hủy diệt vạn vật. Âm thanh vô hình phá tan toàn bộ Phù Văn huyết sắc mà Vương Lâm triệu tập từ trăm man hoang đại lục, đồng thời xé đôi tinh vực cấp năm. Biến âm thanh thành uy lực hủy diệt tuyệt đối.","nguon":["@c1203"]},{"id":"phu-van-huyet-sac","name":"Phù Văn huyết sắc","cn":null,"loai":"than-thong","loaiLabel":"Thần thông","phamCap":null,"hePhai":"Phù tộc","soHuu":["Vương Lâm"],"blurb":"Thuật thần thông của Phù tộc — triệu tập vô số Phù Văn do máu thịt tinh hoa mãnh thú Vân Hải ngưng tụ, có đạo hồn nên uy lực vượt xa đồng loại.","detail":"Vương Lâm triệu tập vô số Phù Văn huyết sắc từ trăm man hoang đại lục. Mỗi Phù Văn do máu thịt tinh hoa mãnh thú Vân Hải ngưng tụ thành, lại chứa đạo hồn nên uy lực vượt xa Phù Văn trên các tinh vực khác. Bị Thủy Đạo Tử dùng Đại Tự Tại Băng Hội Đạo phá hủy, nhưng huyết quang tàn dư được Vương Lâm thu lại tái sử dụng cho Phù Văn Hóa Huyết và tam đại cấm chế dung hợp.","nguon":["@c1203"]},{"id":"phu-van-hoa-huyet","name":"Phù Văn Hóa Huyết","cn":null,"loai":"than-thong","loaiLabel":"Thần thông","phamCap":null,"hePhai":null,"soHuu":["Vương Lâm"],"blurb":"Vương Lâm phun máu yêu dị, hấp thu huyết quang tàn dư từ Phù Văn tan vỡ ngưng tụ thành huyết cầu cực mạnh phóng vào đối thủ.","detail":"Sau khi Phù Văn huyết sắc bị phá hủy, Vương Lâm phun máu yêu dị hấp thu huyết quang tàn dư, ngưng tụ thành huyết cầu tốc độ cực nhanh phóng vào Thủy Đạo Tử. Bị lão quét mắt tan vỡ, nhưng Thủy Đạo Tử chủ động chụp lấy một giọt máu nuốt vào để kiểm tra xem Vương Lâm có phải chủ nhân chuyển thế trùng tu hay không.","nguon":["@c1203"]},{"id":"tam-dai-cam-che-dung-hop","name":"Tam đại cấm chế dung hợp","cn":null,"loai":"bi-thuat","loaiLabel":"Cấm thuật","phamCap":null,"hePhai":null,"soHuu":["Vương Lâm"],"blurb":"Dung hợp Phá Diệt Cấm (phong thiên địa), Sinh Tử Cấm (phong thân thể), Tuế Nguyệt Cấm (phong nguyên thần) — cấm chế không phải pháp thuật, Đệ Tam Bộ cũng phải khựng lại.","detail":"Vương Lâm lần đầu dung hợp cả ba đại cấm chế: Phá Diệt Cấm phong bế thiên địa, Sinh Tử Cấm phong bế thân thể, Tuế Nguyệt Cấm (dưới Lưu Nguyệt nghịch chuyển 5000 năm) phong bế nguyên thần. Dùng trăm man hoang đại lục thu nhỏ bao vây, hấp thu huyết quang và đạo hồn mãnh thú để bù cho cấm chế thứ tư (phong hồn) mà hắn không có, nên chưa thể chính thức quy nhất. Cấm chế không phải pháp thuật, không thuộc quy tắc, nên vẫn khiến Thủy Đạo Tử khựng lại một khoảnh khắc dù bị lão cưỡng chế bước đi phá lần lượt Tuế Nguyệt Cấm → Sinh Tử Cấm → Phá Diệt Cấm.","nguon":["@c1203"]},{"id":"dai-tu-thiet-cat-dao","name":"Đại Tự Thiết Cát Đạo","cn":"大字铁割道","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không Niết cấp","hePhai":"Thủy Đạo Tử","soHuu":["Thủy Đạo Tử"],"blurb":"Đại Tự Thiết Cát Đạo là thần thông của Thủy Đạo Tử, thi triển bằng cách hóa tay phải thành quy tắc cực mạnh cắt đôi thiên địa. Chiêu thức tạo ra khe nứt hình răng cưa nối trời đất, phá hủy tất cả quy tắc và vật chất trong phạm vi.","detail":"Đại Tự Thiết Cát Đạo được Thủy Đạo Tử thi triển bằng cách hóa tay phải thành quy tắc cắt đôi thiên địa. Ở lần thi triển thứ nhất, khe nứt răng cưa bao phủ quanh trường mâu Xạ Thần Xa. Ở lần thứ hai, kèm theo phát ngôn 'phá hủy tất cả quy tắc', một khe nứt khổng lồ nối liền trời đất cắt đôi trường mâu vạn trượng cùng man hoang đại lục, âm thanh chấn động lan đến tậninh vực cấp sáu khiến tu sĩ nơi đó phun máu (@c1204).","thuocTinh":"Quy tắc — cắt","uyLuc":"Phá trường mâu vạn trượng Xạ Thần Xa, cắt đôi đại lục, chấn động lan đến tinh vực cấp sáu","congNang":["Hóa tay phải thành quy tắc cắt đôi thiên địa, tạo khe nứt hình răng cưa phá hủy vật chất và quy tắc","Thi triển hai lần liên tiếp để phá hủy trường mâu vạn trượng Xạ Thần Xa và cắt đôi man hoang đại lục @c1204"],"nguoiTu":[{"ten":"Thủy Đạo Tử","tuChuong":"@c1204","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1204","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Thủy Đạo Tử thi triển hai lần liên tiếp để phá hủy trường mâu vạn trượng Xạ Thần Xa, cắt đôi man hoang đại lục, chấn động lan đến tinh vực cấp sáu.","anchor":"tay phải giống như hóa thành một quy tắc cực mạnh cắt đôi thiên địa"}]},"nguon":["@c1204"],"dacDiem":"Khe nứt hình răng cưa nối trời đất, phá hủy đồng thời cả quy tắc lẫn vật chất"},{"id":"suong-mu-den-chin-dau-quy","name":"Sương mù đen chín đầu quỷ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không Niết cấp","hePhai":"Thủy Đạo Tử","soHuu":["Thủy Đạo Tử"],"blurb":"Thủy Đạo Tử há miệng phun sương mù đen chứa chín đầu quỷ khổng lồ, mỗi đầu có lực lượng tương đương tu sĩ Toái Niết.","detail":"Há miệng phun ra sương mù đen, bên trong hiện chín đầu quỷ khổng lồ. Mỗi đầu quỷ có lực lượng tương đương tu sĩ Toái Niết, đủ quét ngang bất kỳ tinh vực nào. Bị luồng sáng bảy màu Xạ Thần Xa phá hủy hai đầu, bảy đầu còn lại lui không dám ngăn cản.","congNang":["Phun sương mù đen chứa chín đầu quỷ khổng lồ để thôn phệ và ngăn chặn tấn công"],"nguoiTu":[{"ten":"Thủy Đạo Tử","tuChuong":"@c1204","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1204","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Thủy Đạo Tử phun sương mù đen chứa chín đầu quỷ ngăn luồng sáng bảy màu, bị phá hai đầu, bảy đầu còn lại lui.","anchor":"Mỗi đầu quỷ đều có lực lượng tương đương với tu sĩ Toái Niết"}]},"nguon":["@c1204"]},{"id":"than-thong-anh-mat-nham-mo","name":"Thần thông ánh mắt nhắm-mở","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không Niết cấp","hePhai":"Thủy Đạo Tử","soHuu":["Thủy Đạo Tử"],"blurb":"Thủy Đạo Tử liên tục nhắm và mở mắt, mỗi lần mở mắt phá hủy một luồng sáng cầu vồng bằng ánh mắt thực chất.","detail":"Liên tục nhắm và mở mắt, ánh mắt giống như thực chất đảo lên luồng sáng bảy màu, mỗi lần mở ra phá hủy một luồng. Phá bốn trong bảy luồng sáng cầu vồng Xạ Thần Xa.","congNang":["Tấn công bằng ánh mắt thực chất, phá hủy pháp thuật/pháp bảo"],"nguoiTu":[{"ten":"Thủy Đạo Tử","tuChuong":"@c1204","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1204","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Thủy Đạo Tử nhắm-mở mắt phá bốn luồng sáng cầu vồng Xạ Thần Xa.","anchor":"ánh mắt ầm ầm giống như thực chất đảo lên luồng sáng bảy màu trước mặt"}]},"nguon":["@c1204"]},{"id":"luc-dao-tam-trong-tien-thuat","name":"Lục Đạo Tam Trọng Tiên Thuật","cn":"六道三重仙术","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"Chưa rõ","hePhai":"Lục Đạo / Lôi giới","soHuu":["Bạch Phàm"],"blurb":"Tiên thuật thuộc hệ Lục Đạo của Bạch Phàm Lôi giới. Thủy Đạo Tử nhận định nếu đối thủ học được Tam Trọng Thuật thì mới thực sự gây khó khăn cho lão.","detail":"Thủy Đạo Tử nhắc tên khi đánh giá thực lực Lữ Tử Hạo (Vương Lâm), cho rằng ngoài thuật này và Âm Nguyệt Hữu Tình Thuật, mọi thứ khác chỉ là trò hề. Chi tiết công năng chưa được tiết lộ.","nguonGoc":"Bạch Phàm Lôi giới","congNang":[],"tabs":{"tienTrinh":[{"chuong":"@c1205","loai":"nhắc tới","importance":"normal","giaiDoan":"Thủy Đạo Tử nhắc tên khi đánh giá đối thủ","text":"Thủy Đạo Tử nhận xét nếu Lữ Tử Hạo học được Tam Trọng Thuật thì mới gây khó khăn cho lão.","anchor":"Lục Đạo Tam Trọng Tiên Thuật của Bạch Phàm Lôi giới, nếu tên Lữ Tử Hạo này học được Tam Trọng Thuật thì ta sẽ có chút khó khăn"}]},"nguon":["@c1205"]},{"id":"am-nguyet-huu-tinh-thuat","name":"Âm Nguyệt Hữu Tình Thuật","cn":"阴月有情术","loai":"than-thong","loaiLabel":"Tiên thuật","phamCap":"Chưa rõ","hePhai":"Lục Đạo / Lôi giới","soHuu":[],"blurb":"Tiên thuật cực kỳ có danh tiếng năm xưa trong hệ Lục Đạo. Thủy Đạo Tử nhận xét nếu đối thủ học được cũng gây phiền phức.","detail":"Thủy Đạo Tử nhắc đến như một trong số ít thuật có thể gây phiền phức cho lão ngoài Tam Trọng Thuật. Chi tiết công năng chưa được tiết lộ.","nguonGoc":"Lục Đạo, Lôi giới","congNang":[],"tabs":{"tienTrinh":[{"chuong":"@c1205","loai":"nhắc tới","importance":"normal","giaiDoan":"Thủy Đạo Tử nhắc tên khi đánh giá đối thủ","text":"Thủy Đạo Tử nhận xét đây là thuật cực kỳ có danh tiếng năm xưa trong Lục Đạo, nếu đối thủ học được cũng gây phiền phức.","anchor":"dù hắn học được Âm Nguyệt Hữu Tình Thuật cực kỳ có danh tiếng năm xưa thì cũng có chút phiền phức"}]},"nguon":["@c1205"]},{"id":"dai-tu-tai-tuyet-khong-dao","name":"Đại Tự Tại Tuyệt Không Đạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đệ Tam Bộ cấp","hePhai":"Đệ Tam Bộ","soHuu":["Thủy Đạo Tử"],"blurb":"Đại Tự Tại Tuyệt Không Đạo là thần thông cực mạnh thuộc đạo pháp Đệ Tam Bộ, huyễn hóa hàng loạt đường cong bạch sắc giao thoa tạo thành hình thoi khổng lồ trong tinh không. Toàn bộ năng lượng tinh không phạm vi ngàn vạn trượng bị dồn nén, co rút cực nhanh xuống trăm trượng rồi đập thẳng vào mục tiêu.","detail":"Xuất từ đạo pháp Đệ Tam Bộ, Đại Tự Tại Tuyệt Không Đạo được Thủy Đạo Tử thi triển. Khi phát động, thần thông huyễn hóa hàng loạt đường cong bạch sắc giao thoa nhau tạo hình thoi khổng lồ phạm vi ngàn vạn trượng giữa tinh không, sau đó co rút cực nhanh xuống trăm trượng, dồn nén toàn bộ lực lượng tinh không đập thẳng vào mục tiêu (@c1206). Uy lực ngang hơn mười tu chân tinh đồng thời tan vỡ, đủ sức hủy diệt hoàn toàn thân thể và nguyên thần Toái Niết, chấn động lan từ tinh vực cấp năm đến cấp tám.","thuocTinh":"Không gian, Dồn nén","nguonGoc":"Đạo pháp Đệ Tam Bộ","uyLuc":"Ngang hơn mười tu chân tinh đồng thời tan vỡ, hủy diệt hoàn toàn thân thể và nguyên thần Toái Niết, chấn động từ tinh vực cấp năm đến cấp tám.","dacDiem":"Dồn nén lực lượng tinh không phạm vi ngàn vạn trượng thành hình thoi, co rút xuống trăm trượng rồi đập vào mục tiêu.","congNang":["Huy động năng lượng tinh không phạm vi ngàn vạn trượng dồn nén thành hình thoi đập vào mục tiêu","Huyễn hóa hàng loạt đường cong bạch sắc giao thoa tạo hình thoi khổng lồ, co rút từ ngàn vạn trượng xuống trăm trượng để dồn nén lực lượng (@c1206)"],"nguoiTu":[{"ten":"Thủy Đạo Tử","tuChuong":"@c1206","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1206","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Thủy Đạo Tử thi triển Đại Tự Tại Tuyệt Không Đạo, hình thoi co rút từ ngàn vạn trượng xuống trăm trượng, nghiền nát hoàn toàn thân thể Vương Lâm và hủy diệt Tam Xoa Kích.","anchor":"Đại Tự Tại Tuyệt Không Đạo, tuyệt diệt tất cả sinh linh trước mặt cho ta"}]},"nguon":["@c1206"]},{"id":"co-than-thuat-tieu-diet-sinh-linh","name":"Cổ Thần thuật — tiêu diệt tất cả sinh linh","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Cổ Thần thuật là thần thông của bộ tộc Cổ Thần, dùng sinh cơ trong thân thể đổi lấy lực lượng thiên địa cực mạnh ẩn trong nắm đấm tấn công. Cái giá phải trả là thân thể nhanh chóng già cỗi.","detail":"Cổ Thần thuật là thần thông đặc trưng của bộ tộc Cổ Thần — một bộ tộc tuy không sở hữu nhiều thần thông nhưng mỗi thứ đều cực kỳ mạnh mẽ, không phải tu sĩ thông thường có thể giải thích được. Bản chất công pháp là tiêu tán sinh cơ trong thân thể để hóa thành lực lượng thiên địa cực mạnh dồn vào nắm đấm, mỗi quyền đánh ra đều khiến thân thể già cỗi nhanh chóng. Vương Lâm từng hóa Cổ Thần thất tinh thi triển công pháp này, đánh liên tục 100 quyền tấn công Thủy Đạo Tử (@c1207).","congNang":["Dùng sinh cơ trong thân thể hóa thành lực lượng thiên địa cực mạnh ẩn trong nắm đấm tấn công @c1207","Hóa Cổ Thần thất tinh thi triển, đánh liên tục 100 quyền @c1207"],"uyLuc":"Đủ phá vỡ tinh vực cấp năm","dacDiem":"Tiêu tán sinh cơ, thân thể già cỗi nhanh chóng","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1207","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1207","loai":"thi triển","importance":"major","giaiDoan":"Vương Lâm lần đầu thi triển toàn lực","text":"Vương Lâm hóa Cổ Thần thất tinh thi triển Cổ Thần thuật dùng sinh cơ đổi lực lượng, đánh liên tục 100 quyền tấn công Thủy Đạo Tử, phá tan sương mù và khiến tinh vực cấp năm suýt tan vỡ.","anchor":"Cổ Thần thuật, tiêu diệt tất cả sinh linh!"}]},"nguon":["@c1207"]},{"id":"thuy-dao-thon-hu-thuat","name":"Thủy Đạo Thôn Hư Thuật","cn":"水道吞虛術","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Thủy Đạo","soHuu":["Thủy Đạo Tử"],"blurb":"Thần thông của Thủy Đạo Tử, tạo vòng xoáy hóa thành miệng khổng lồ thôn phệ để nuốt tấn công đối phương.","detail":"Thủy Đạo Tử triển khai tạo vòng xoáy thôn phệ để nuốt trăm quyền của Vương Lâm, nhưng sóng gợn từ trăm quyền tan vỡ cuốn ngược vòng xoáy vào thân lão gây thương tích.","congNang":["Tạo vòng xoáy hóa miệng khổng lồ thôn phệ để nuốt tấn công đối thủ"],"nguoiTu":[{"ten":"Thủy Đạo Tử","tuChuong":"@c1208","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1208","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển chống trăm quyền","text":"Thủy Đạo Tử triển khai Thủy Đạo Thôn Hư Thuật tạo vòng xoáy thôn phệ để nuốt trăm quyền của Vương Lâm nhưng bị sóng gợn cuốn ngược gây thương.","anchor":"Thiên Địa Vô Cực, Thủy Đạo Thôn Hư Thuật"}]},"nguon":["@c1208"]},{"id":"dai-tu-tai-luan-hoi","name":"Đại Tự Tại Luân Hồi","cn":"大自在輪迴","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Đại Tự Tại","soHuu":["Thủy Đạo Tử"],"blurb":"Đại Tự Tại Luân Hồi là thần thông cấm chế của Thủy Đạo Tử, rút quy tắc luân hồi trời đất tạo thành Pháp Vi Luân khổng lồ giữa tinh không, nhắm giết mục tiêu một trăm lần để phá vỡ khả năng trọng sinh/luân hồi. Thủy Đạo Tử triển khai công pháp này để đối phó Vương Lâm nhưng bị phá giải.","detail":"Đại Tự Tại Luân Hồi được Thủy Đạo Tử triển khai sau khi bị trăm quyền thương (@c1208). Công pháp rút quy tắc luân hồi của trời đất, tạo nên một Pháp Vi Luân hư ảo khổng lồ giữa tinh không, định giết Vương Lâm trăm lần nhằm phá vỡ khả năng trọng sinh của đối thủ. Lần thi triển này bị lão già phân thân gió dùng cánh tay gió chụp tan.","congNang":["Rút quy tắc luân hồi trời đất tạo Pháp Vi Luân khổng lồ giữa tinh không @c1208","Giết mục tiêu một trăm lần nhằm phá vỡ khả năng trọng sinh/luân hồi @c1208"],"nguoiTu":[{"ten":"Thủy Đạo Tử","tuChuong":"@c1208","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1208","loai":"thi triển","importance":"major","giaiDoan":"Thi triển định giết Vương Lâm","text":"Thủy Đạo Tử triển khai Đại Tự Tại Luân Hồi tạo Pháp Vi Luân khổng lồ giữa tinh không nhằm giết Vương Lâm trăm lần phá vỡ trọng sinh. Bị lão già phân thân gió dùng cánh tay gió phá tan.","anchor":"Đại Tự Tại Luân Hồi! Lão phu phá vỡ muôn đời luân hồi của ngươi, cho ngươi chết một trăm lần"}]},"nguon":["@c1208"],"uyLuc":"Tạo Pháp Vi Luân hư ảo khổng lồ mang quy tắc luân hồi giữa tinh không, định giết mục tiêu trăm lần để triệt tiêu khả năng trọng sinh.","dacDiem":"Thần thông cấm chế dựa trên quy tắc luân hồi trời đất, biểu hiện qua Pháp Vi Luân khổng lồ."},{"id":"mot-tram-quyen","name":"Một Trăm Quyền","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật / Tuyệt chiêu","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Một Trăm Quyền là tuyệt chiêu liều chết toàn lực của Vương Lâm, đỉnh phong cả đời tu đạo hai ngàn năm.Ông dồn toàn bộ tinh thần, nguyên lực, uy lực giọt máu Thiết kiếm cùng ý niệm tự sát vào trăm quyền hóa thành hình bướm lao vào Thủy Đạo Tử.","detail":"Đây là tuyệt chiêu Vương Lâm thi triển bằng cách dồn toàn bộ tu vi hai ngàn năm, tinh thần, nguyên lực và ý niệm tự sát vào trăm quyền, hóa thành hình bướm mang khí thế kinh thiên động địa lao vào Thủy Đạo Tử @c1208. Trăm quyền gây thương tích cho Đệ Tam Bộ, đồng thời hủy diệt sương mù, mãnh thú, man hoang đại lục cấp sáu và tinh vực cấp bảy xung quanh. Cái giá phải trả là trái tim Vương Lâm vỡ tung và hai mắt mất sáng.","congNang":["Tuyệt chiêu liều chết toàn lực, dồn mọi tinh thần nguyên lực ý niệm vào trăm quyền","Dồn toàn bộ tu vi hai ngàn năm hóa thành hình bướm lao vào đối thủ @c1208","Gây thương tích cho Đệ Tam Bộ","Hủy diệt sương mù, mãnh thú, man hoang đại lục cấp sáu và tinh vực cấp bảy xung quanh"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1208","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1208","loai":"thi triển","importance":"major","giaiDoan":"Thi triển chống Thủy Đạo Tử","text":"Vương Lâm dồn toàn bộ tu vi hai ngàn năm vào trăm quyền hóa hình bướm lao vào Thủy Đạo Tử. Gây thương tích cho Đệ Tam Bộ, phá hủy đại lục cấp sáu và tinh vực cấp bảy. Trái tim Vương Lâm vỡ tung, hai mắt mất sáng.","anchor":"Một trăm quyền này ẩn giấu sinh cơ vô tận của Vương Lâm, ẩn chứa tất cả những gì hắn đã tu đạo suốt hai ngàn năm qua"}]},"nguon":["@c1208"],"uyLuc":"Gây thương tích cho Đệ Tam Bộ, hủy diệt man hoang đại lục cấp sáu và tinh vực cấp bảy xung quanh, đổi lại trái tim vỡ tung và hai mắt mất sáng.","dacDiem":"Tuyệt chiêu liều chết dồn toàn bộ tinh thần, nguyên lực, uy lực giọt máu Thiết kiếm và ý niệm tự sát, hóa thành hình bướm mang khí thế kinh thiên động địa."},{"id":"ban-nguyen-sinh-tu","name":"Bản nguyên Sinh Tử","cn":"生死本源","loai":"cong-phap","loaiLabel":"Bản nguyên","phamCap":"Đệ Tam Bộ (bản nguyên nhập đạo)","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Bản nguyên Sinh Tử là luồng bản nguyên thứ nhất do Vương Lâm tự cảm ngộ trong nguy cơ sinh tử trước Thủy Đạo Tử. Khi đối mặt cái chết, hắn lĩnh ngộ rằng sau sinh cơ là tử khí, tử khí toàn thân bùng ra tạo thành vòng xoáy phá âm dương phá luân hồi, từ đó sinh ra lực lượng bản nguyên.","detail":"Khác với bản nguyên lấy từ Chiến Tự Thiếp vốn là ngoại lực, Bản nguyên Sinh Tử là bản nguyên do Vương Lâm tự mình cảm ngộ. Khi đối mặt cái chết trước Thủy Đạo Tử (@c1209), hắn lĩnh ngộ rằng sau sinh cơ là tử khí, có thể dùng tử khí toàn thân đánh ra đòn cuối cùng. Tử khí tuôn ra thành vòng xoáy khổng lồ, phá vỡ âm dương, phá nát luân hồi, trong đó sinh ra lực lượng bản nguyên. Đây là một trong ba luồng bản nguyên, nếu đại thành cùng hai luồng kia có thể mở khe cửa Đệ Tam Bộ và nhập đạo thành Chí Tôn. Tính tới mốc mới nhất bản nguyên này còn rất yếu, cần tích lũy đại thành.","congNang":["Cảm ngộ tử khí toàn thân, bùng ra tạo vòng xoáy khổng lồ phá vỡ âm dương, phá nát luân hồi, trong đó sinh ra lực lượng bản nguyên @c1209","Mở khe cửa Đệ Tam Bộ; nếu đại thành cùng hai luồng bản nguyên còn lại có thể nhập đạo thành Chí Tôn"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1209","tangDatToi":"Mới cảm ngộ, còn yếu","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1209","loai":"xuat-hien","importance":"major","giaiDoan":"Vương Lâm cảm ngộ lần đầu","text":"Trong nguy cơ sinh tử trước Thủy Đạo Tử, Vương Lâm lĩnh ngộ tử khí bùng ra tạo vòng xoáy phá âm dương phá luân hồi, sinh ra luồng bản nguyên thứ nhất — Sinh Tử. Đây là bản nguyên tự cảm ngộ, khác ngoại lực từ Chiến Tự Thiếp.","anchor":"khoảnh khắc khi tử khí toàn thân bùng ra, hắn lại cảm ngộ được. lực bản nguyên của chính mình"}]},"nguon":["@c1209"],"uyLuc":"Tử khí toàn thân bùng ra thành vòng xoáy khổng lồ, phá vỡ âm dương, phá nát luân hồi, sinh ra lực lượng bản nguyên @c1209","dacDiem":"Bản nguyên do tự mình cảm ngộ trong nguy cơ sinh tử, khác với bản nguyên ngoại lực lấy từ Chiến Tự Thiếp; lấy tử khí sau sinh cơ làm gốc, hiện còn rất yếu cần tích lũy đại thành"},{"id":"ban-nguyen-nhan-qua","name":"Bản nguyên Nhân Quả","cn":"因果本源","loai":"cong-phap","loaiLabel":"Bản nguyên","phamCap":"Đệ Tam Bộ (bản nguyên nhập đạo)","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Bản nguyên Nhân Quả là luồng bản nguyên thứ hai Vương Lâm cảm ngộ khi toái tinh, phá vỡ sáu Cổ Thần tinh điểm khiến vòng xoáy thứ hai bùng ra khí tức Cổ Thần. Từ chính hành động phá rồi lại lập ấy mà sinh ra bản nguyên nhân quả, dùng để bổ sung cho việc nhập đạo Đệ Tam Bộ.","detail":"Bản nguyên này khởi nguồn khi sáu tinh điểm vương tộc Cổ Thần trên mi tâm Vương Lâm — kể cả tinh điểm thứ sáu vừa khôi phục chưa thành hình — hoàn toàn tan vỡ, để rồi vòng xoáy thứ hai bùng phát khí tức Cổ Thần. Cái lý phá rồi lại lập chính là nhân quả, vì thế mà thành tên. Tại thời điểm mới sinh, luồng bản nguyên còn rất yếu, cần tích lũy mới có thể đại thành, và vai trò của nó là bổ sung bản nguyên phục vụ cho việc nhập đạo Đệ Tam Bộ.","congNang":["Bổ sung bản nguyên phục vụ nhập đạo Đệ Tam Bộ","Sinh ra từ việc chủ động phá vỡ toàn bộ sáu Cổ Thần tinh điểm, khiến vòng xoáy thứ hai bùng ra khí tức Cổ Thần @c1209"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1209","tangDatToi":"Mới cảm ngộ, còn yếu","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1209","loai":"xuat-hien","importance":"major","giaiDoan":"Vương Lâm toái tinh cảm ngộ","text":"Vương Lâm chủ động phá vỡ toàn bộ sáu Cổ Thần tinh điểm (toái tinh), vòng xoáy thứ hai bùng ra khí tức Cổ Thần, cảm ngộ bản nguyên Nhân Quả.","anchor":"Trong sinh tử, Cổ Thần Vương Lâm toái tinh, nhưng hắn lại cảm ngộ ra luồng lực lượng bản nguyên thứ hai trong đời"}]},"nguon":["@c1209"],"dacDiem":"Sinh ra từ lý phá rồi lại lập — tức nhân quả; khi mới thành còn rất yếu, cần tích lũy mới đại thành."},{"id":"ban-nguyen-that-gia","name":"Bản nguyên Thật Giả","cn":"真假本源","loai":"cong-phap","loaiLabel":"Bản nguyên","phamCap":"Đệ Tam Bộ (bản nguyên nhập đạo)","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Bản nguyên Thật Giả là luồng bản nguyên thứ ba Vương Lâm cảm ngộ khi quy tắc tinh do ý cảnh tan vỡ, ý cảnh thật giả đạt minh ngộ. Cùng với Sinh Tử và Nhân Quả, ba luồng bản nguyên đồng thời bùng phát tạo thành điều chưa từng có trong thiên địa.","detail":"Bản nguyên Thật Giả hình thành khi quy tắc tinh do ý cảnh trên mi tâm Vương Lâm tan vỡ, hóa thành vòng xoáy thứ bao phủ bên ngoài thân thể (@c1209). Đây là luồng bản nguyên thứ ba, hợp cùng Sinh Tử và Nhân Quả tạo thành ba luồng bản nguyên cùng bùng ra — điều chưa từng có trong thiên địa, vượt qua Chưởng Tôn và Thanh Lâm vốn chỉ có hai luồng. Nếu ba luồng đại thành nhập đạo, Vương Lâm sẽ đạt Không Kiếp Đệ Tam Bộ, trở thành Chí Tôn không ai chống nổi.","congNang":["Nếu ba luồng bản nguyên (Sinh Tử, Nhân Quả, Thật Giả) đại thành nhập đạo thì đạt Không Kiếp Đệ Tam Bộ, trở thành Chí Tôn không ai chống nổi @c1209"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1209","tangDatToi":"Mới cảm ngộ, còn yếu","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1209","loai":"xuat-hien","importance":"major","giaiDoan":"Vương Lâm cảm ngộ bản nguyên thứ ba","text":"Quy tắc tinh do ý cảnh thật giả tan vỡ thành vòng xoáy thứ ba, ý cảnh thật giả đạt minh ngộ. Ba luồng bản nguyên chưa từng có trong thiên địa.","anchor":"Thật giả chính là luồng bản nguyên thứ ba"}]},"nguon":["@c1209"],"uyLuc":"Nếu ba luồng đại thành nhập đạo sẽ đạt Không Kiếp Đệ Tam Bộ, thành Chí Tôn không ai chống nổi.","dacDiem":"Luồng bản nguyên thứ ba do quy tắc tinh do ý cảnh thật giả tan vỡ mà thành, hóa thành vòng xoáy thứ ba bao phủ bên ngoài thân thể; cùng Sinh Tử và Nhân Quả tạo thành ba luồng bản nguyên chưa từng có, vượt qua các cao thủ chỉ có hai luồng."},{"id":"nam-dao-ban-nguyen","name":"Năm đạo bản nguyên","cn":"五道本源","loai":"cong-phap","loaiLabel":"Hệ thống bản nguyên","phamCap":"Vượt Toái Niết, cận Đệ Tứ Bộ","hePhai":"Bản nguyên","soHuu":["Vương Lâm"],"blurb":"Hệ thống năm đạo bản nguyên của Vương Lâm gồm sinh tử, nhân quả, chân giả, hỏa diễm và lôi đình — số lượng bản nguyên nhiều nhất từ cổ chí kim trong Thái Cổ Tinh Thần. Tính tới thời điểm hé lộ, ngoài ba đạo đã lộ, Vương Lâm còn ẩn giấu hai bản nguyên hỏa diễm và lôi đình.","detail":"Năm đạo bản nguyên do Vương Lâm tự cảm ngộ và tích lũy qua nhiều cơ duyên, gồm: (1) Sinh tử — cảm ngộ khi sinh cơ sụp đổ; (2) Nhân quả — toái diệt Cổ Thần tinh; (3) Chân giả — ý cảnh chi tinh tiêu tán; (4) Hỏa diễm — từ ngọn lửa Chu Tước ba lần lột xác; (5) Lôi đình — từ cắn nuốt nửa Thái Cổ Lôi Long và hấp thụ thiên lôi tộc thái cổ. Số lượng bản nguyên vượt qua cả Toái Niết, Thanh Lâm và tôn sư Phong giới. Trong ba đạo đã lộra ngoài là sinh tử, nhân quả và chân giả, còn hỏa diễm cùng lôi đình được ẩn giấu (@c1210). Nếu bước vào Đệ Tam Bộ với năm bản nguyên đại thành, người sở hữu sẽ có tư cách tiến tới Đệ Tứ Bộ truyền thuyết.","thuocTinh":"Tổng hợp (sinh tử, nhân quả, chân giả, hỏa diễm, lôi đình)","nguonGoc":"Tự cảm ngộ và tích lũy qua nhiều cơ duyên","dacDiem":"Số lượng bản nguyên nhiều nhất từ cổ chí kim trong Thái Cổ Tinh Thần","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1210","tangDatToi":"Năm đạo, chưa đại thành","trangThai":"tan nát sau đòn đồng quy vu tận"}],"congNang":["Năm bản nguyên lực đại thành có thể bước vào Đệ Tứ Bộ truyền thuyết","Hủy năm bản nguyên đổi một kích uy lực cận Đệ Tam Bộ, vượt Xạ Thần Xa, đủ giết tu sĩ Toái Niết và Thanh Long Thánh Hoàng","Ẩn giấu hai bản nguyên hỏa diễm và lôi đình ngoài ba đạo đã lộ (@c1210)"],"tabs":{"tienTrinh":[{"chuong":"@c1210","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lộ toàn bộ năm đạo bản nguyên","text":"Tiết lộ ngoài ba đạo đã lộ (sinh tử, nhân quả, chân giả), Vương Lâm còn ẩn bản nguyên hỏa diễm và lôi đình. Hủy năm đạo để đánh ra đòn mạnh nhất đời, uy lực cận Đệ Tam Bộ.","anchor":"khiến Vương Lâm trở thành chí tôn từ cổ chí kim có được nhiều bản nguyên nhất"}]},"capNhatToi":"@c1210","dinhDanh":"goc","nguon":["@c1210"],"uyLuc":"Hủy năm bản nguyên đổi một kích uy lực cận Đệ Tam Bộ, vượt Xạ Thần Xa, đủ giết tu sĩ Toái Niết và Thanh Long Thánh Hoàng"},{"id":"he-thong-hoa-diem","name":"Hệ thống hỏa diễm","cn":"火焰体系","loai":"than-thong","loaiLabel":"Thần thông / Cảnh giới hỏa","phamCap":"Đạo hỏa (tầng cao nhất)","hePhai":"Hỏa","soHuu":["Vương Lâm"],"blurb":"Ba tầng hỏa diễm: nộ hỏa, phần hỏa, đạo hỏa. Vương Lâm sau ba lần lột xác lửa Chu Tước đã nắm quyền điều khiển hỏa diễm thiên hạ.","detail":"Nộ hỏa: mọi người đều có, vô hình, thiêu chết nếu không kiểm soát. Phần hỏa: thiêu đốt ý tứ, kinh thiên động địa. Đạo hỏa: đốt cháy ý cảnh đối phương, gần đạo thuật. Vương Lâm sau ba lần lột xác lửa Chu Tước đạt cảnh giới khiến mọi thần thông hỏa diễm phải khuất phục, nắm quyền điều khiển hỏa diễm thiên hạ, có thể nhen nhóm nộ hỏa trong thân người khác để giết.","cacTang":[{"ten":"Nộ hỏa","moTa":"Mọi người đều có, vô hình, thiêu chết nếu không kiểm soát","chuong":"@c1210"},{"ten":"Phần hỏa","moTa":"Thiêu đốt ý tứ, kinh thiên động địa","chuong":"@c1210"},{"ten":"Đạo hỏa","moTa":"Đốt cháy ý cảnh đối phương, gần đạo thuật","chuong":"@c1210"}],"congNang":["Điều khiển hỏa diễm trong thân người khác, nhen nhóm nộ hỏa giết người","Mọi thần thông hỏa diễm phải khuất phục trước người đạt đỉnh hỏa"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1210","tangDatToi":"Đạo hỏa (đỉnh, sau ba lần lột xác lửa Chu Tước)","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1210","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Giải thích ba tầng hỏa diễm","text":"Giải thích hệ thống ba tầng nộ hỏa, phần hỏa, đạo hỏa. Vương Lâm đạt đỉnh hỏa sau ba lần lột xác lửa Chu Tước.","anchor":"Hết thảy thần thông hỏa diễm trước mặt hắn đều phải khuất phục"}]},"capNhatToi":"@c1210","dinhDanh":"goc","nguon":["@c1210"]},{"id":"ban-nguyen-loi-dinh","name":"Bản nguyên lôi đình","cn":"雷霆本源","loai":"cong-phap","loaiLabel":"Bản nguyên","phamCap":"Chưa đại thành (người thay thế)","hePhai":"Lôi","soHuu":["Vương Lâm"],"blurb":"Bản nguyên thứ năm ẩn sâu trong Vương Lâm, nguồn gốc từ cắn nuốt nửa Thái Cổ Lôi Long và hấp thụ thiên lôi tộc thái cổ.","detail":"Hiện Vương Lâm là người thay thế nắm quyền điều khiển lôi đình thiên địa. Nếu cắn nuốt được chín loại lôi lực sơ khai sẽ bỏ chữ người thay thế, trở thành chủ nhân lôi đình, bản nguyên lôi đại thành.","congNang":["Điều khiển lôi đình thiên địa (ở mức người thay thế)","Đại thành khi cắn nuốt đủ chín loại lôi lực sơ khai → trở thành chủ nhân lôi đình"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1210","tangDatToi":"Người thay thế, chưa đại thành","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1210","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Tiết lộ bản nguyên lôi đình ẩn giấu","text":"Bản nguyên lôi đình từ cắn nuốt nửa Thái Cổ Lôi Long và hấp thụ thiên lôi tộc thái cổ. Cần cắn nuốt chín loại lôi lực sơ khai để đại thành.","anchor":"cắn nuốt được chín loại lôi lực sơ khai trong thiên địa thì hắn có thể trở thành chủ nhân lôi đình"}]},"capNhatToi":"@c1210","dinhDanh":"goc","nguon":["@c1210"]},{"id":"lac-an-thai-co-tinh-than","name":"Lạc ấn Thái Cổ Tinh Thần","cn":"烙印太古星辰","loai":"than-thong","loaiLabel":"Thần thông / Truyền thừa","phamCap":"Không rõ (lực lượng Thái Cổ Tinh Thần)","hePhai":"Thái Cổ Tinh Thần","soHuu":["Vương Lâm"],"blurb":"Lạc ấn Thái Cổ Tinh Thần là dấu ấn do Phong giới tôn sư tạo ra bằng cách trích xuất lực lượng Thái Cổ Tinh Thần còn lưu giữ bên trong Thiên Nghịch. Lạc ấn được đóng trực tiếp vào hồn phách người nhận, giúp tiến vào đạo cảnh và lĩnh ngộ diễn biến thiên đạo.","detail":"Lạc ấn được Phong giới tôn sư tạo ra bằng cách trích xuất lực lượng Thái Cổ Tinh Thần còn lưu giữ bên trong Thiên Nghịch, hóa thành dấu ấn đóng trực tiếp vào hồn phách người nhận (@c1213). Công dụng của lạc ấn là giúp người nhận tiến vào đạo cảnh và lĩnh ngộ diễn biến thiên đạo. Vương Lâm là người thứ ba và cũng là người cuối cùng nhận được ân huệ từ Phong giới tôn sư.","thuocTinh":"Thái Cổ Tinh Thần","nguonGoc":"Lực lượng Thái Cổ Tinh Thần trích từ Thiên Nghịch, do Phong giới tôn sư tạo","congNang":["Đóng vào hồn phách người nhận @c1213","Giúp tiến vào đạo cảnh","Hiểu diễn biến thiên đạo"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1213","tangDatToi":"Vừa nhận","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1213","loai":"xuat-hien","importance":"major","giaiDoan":"Phong giới tôn sư ban lạc ấn cho Vương Lâm","text":"Phong giới tôn sư trích xuất lực lượng Thái Cổ Tinh Thần từ Thiên Nghịch, hóa thành lạc ấn đóng vào hồn phách Vương Lâm, giúp tiến vào đạo cảnh. Tôn sư sau đó hoàn toàn tiêu tán.","anchor":"có thể từ trong Thiên Nghịch lấy ra lực lượng của Thái Cổ Tinh Thần, hóa thành lạc ấn đóng vào hồn phách ngươi"}]},"nguon":["@c1213"]}]};
